import React from 'react';
import { BrowserRouter as Router, Route, Switch } from 'react-router-dom';
import EmployeeList from './components/EmployeeList';
import AddEmployee from './components/AddEmployee';
import EditEmployee from './components/EditEmployee';
import CompanyItemList from './components/CompanyItemList';
import AddCompanyItem from './components/AddCompanyItem';
import EditCompanyItem from './components/EditCompanyItem';
import Login from './components/Login';
import Home from './components/Home';
import ProtectedRoute from './components/ProtectedRoute';

function App() {
  return (
    <Router>
      <div className="App">
        <Switch>
          <Route exact path="/" component={Login} />
          <ProtectedRoute path="/home" component={Home} />
          <ProtectedRoute path="/employees" component={EmployeeList} />
          <ProtectedRoute path="/add-employee" component={AddEmployee} />
          <ProtectedRoute path="/edit-employee/:id" component={EditEmployee} />
          <ProtectedRoute path="/company-items" component={CompanyItemList} />
          <ProtectedRoute path="/add-company-item" component={AddCompanyItem} />
          <ProtectedRoute path="/edit-company-item/:id" component={EditCompanyItem} />
        </Switch>
      </div>
    </Router>
  );
}

export default App;
